import React from "react";
import { useParams } from "react-router-dom";
import {
  Container,
  Typography,
  Grid,
  Paper,
  Avatar,
  Divider,
  List,
  ListItem,
  ListItemText,
  Button,
  Box,
} from "@mui/material";

import { doctors } from "../data/doctors"; // fixed import

const DoctorProfile = () => {
  const { doctorId } = useParams(); // ← must be INSIDE the component

  const doctor = doctors.find((d) => d.id === Number(doctorId));

  if (!doctor) {
    return (
      <Container sx={{ py: 8 }}>
        <Typography variant="h5" align="center" color="error">
          Doctor not found
        </Typography>
      </Container>
    );
  }

    return (
      
        
    <Container
      maxWidth="xl" // ← Change this: md → xl (makes page much wider)
      sx={{
        py: 10, // more top/bottom breathing room
        px: { xs: 2, md: 6 }, // more side padding on larger screens
      }}
    >
      <Paper
        elevation={8} // ← stronger shadow = feels more prominent
        sx={{
          p: { xs: 4, md: 8 }, // ← MUCH more padding inside the card
          borderRadius: 4,
          maxWidth: 1400, // ← force the card to be wider (adjust 900–1200)
          mx: "auto", // center it
          backgroundColor: "#ffffff", // clean white
          boxShadow: "0 12px 40px rgba(0,0,0,0.12)", // deeper shadow
        }}
      >
        <Grid container spacing={6}>
          {" "}
          // ← more space between photo & details
          {/* Left – photo area – make it wider */}
          <Grid
            item
            xs={15}
            md={5} // ← was 4 → now 5 (photo side gets more width)
            sx={{
              textAlign: "center",
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <Avatar
              src={doctor.image}
              alt={doctor.name}
              sx={{
                width: { xs: 400, md: 580 }, // ← photo much bigger on desktop
                height: { xs: 240, md: 380 },
                mb: 4,
                border: "6px solid #e3f2fd", // light blue border – looks nice
                boxShadow: "0 8px 32px rgba(25,118,210,0.2)",
              }}
            />
            <Typography
              variant="h3" // ← name much bigger
              gutterBottom
              sx={{ fontWeight: "bold" }}
            >
              {doctor.name}
            </Typography>
            <Typography
              variant="h5" // ← specialty bigger
              color="primary"
              gutterBottom
            >
              {doctor.specialty}
            </Typography>
          </Grid>
          {/* Right – details area */}
          <Grid item xs={12} md={7}>
            <Typography
              variant="h4" // ← section title bigger
              gutterBottom
              sx={{ mb: 4, fontWeight: 600 }}
            >
              Professional Details
            </Typography>
            <Divider sx={{ mb: 4, borderColor: "#1976d2" }} />

            <List disablePadding>
              <ListItem sx={{ py: 2.5 }}>
                {" "}
                // ← more vertical space per row
                <ListItemText
                  primary={<Typography variant="h6">Experience</Typography>}
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.15rem" }}>
                      {doctor.experience}
                    </Typography>
                  }
                />
              </ListItem>
              <ListItem sx={{ py: 2.5 }}>
                <ListItemText
                  primary={<Typography variant="h6">Qualification</Typography>}
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.15rem" }}>
                      {doctor.qualification}
                    </Typography>
                  }
                />
              </ListItem>
              <ListItem sx={{ py: 2.5 }}>
                <ListItemText
                  primary={<Typography variant="h6">Availability</Typography>}
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.15rem" }}>
                      {doctor.availability}
                    </Typography>
                  }
                />
              </ListItem>
              <ListItem sx={{ py: 2.5, alignItems: "flex-start" }}>
                <ListItemText
                  primary={<Typography variant="h6">About</Typography>}
                  secondary={
                    <Typography
                      variant="body1"
                      sx={{
                        fontSize: "1.15rem",
                        lineHeight: 1.8,
                      }}
                    >
                      {doctor.bio}
                    </Typography>
                  }
                />
              </ListItem>
            </List>

            <Box sx={{ mt: 8, textAlign: "center" }}>
              {" "}
              // ← more space above button
              <Button
                variant="contained"
                color="primary"
                size="large"
                sx={{
                  py: 2.5, // taller button
                  px: 8, // wider button
                  fontSize: "1.3rem", // bigger text inside button
                  borderRadius: 3,
                }}
              >
                Book Appointment
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Paper>
    </Container>
  );
};

export default DoctorProfile;
